import{_ as e,c as i,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Múltiples Canales y Plataformas | Tutorial de Clawdbot","description":"Aprende a configurar y usar el sistema multicanal de Clawdbot, incluyendo plataformas como WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS y Android.","frontmatter":{"title":"Múltiples Canales y Plataformas | Tutorial de Clawdbot","sidebarTitle":"Integrar Herramientas de Chat Comunes","subtitle":"Múltiples Canales y Plataformas","description":"Aprende a configurar y usar el sistema multicanal de Clawdbot, incluyendo plataformas como WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS y Android.","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"es/moltbot/moltbot/platforms/index.md","filePath":"es/moltbot/moltbot/platforms/index.md"}'),n={name:"es/moltbot/moltbot/platforms/index.md"};function r(l,a,t,c,d,u){return o(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="multiples-canales-y-plataformas" tabindex="-1">Múltiples Canales y Plataformas <a class="header-anchor" href="#multiples-canales-y-plataformas" aria-label="Permalink to &quot;Múltiples Canales y Plataformas&quot;">​</a></h1><p>Clawdbot admite múltiples canales de comunicación y plataformas a través de un plano de control Gateway unificado, permitiéndote interactuar con el asistente de IA en interfaces que ya conoces.</p><h2 id="vision-general-del-capitulo" tabindex="-1">Visión General del Capítulo <a class="header-anchor" href="#vision-general-del-capitulo" aria-label="Permalink to &quot;Visión General del Capítulo&quot;">​</a></h2><p>Este capítulo presenta todos los canales de comunicación y plataformas compatibles con Clawdbot, incluyendo aplicaciones de mensajería instantánea (WhatsApp, Telegram, Slack, Discord, etc.), nodos móviles (iOS, Android) y aplicaciones de escritorio (macOS). Aprende a configurar estos canales para que el asistente de IA se integre perfectamente en tu flujo de trabajo diario.</p><h2 id="navegacion-de-subpaginas" tabindex="-1">Navegación de Subpáginas <a class="header-anchor" href="#navegacion-de-subpaginas" aria-label="Permalink to &quot;Navegación de Subpáginas&quot;">​</a></h2><h3 id="vision-general-de-canales" tabindex="-1">Visión General de Canales <a class="header-anchor" href="#vision-general-de-canales" aria-label="Permalink to &quot;Visión General de Canales&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">Visión General del Sistema Multicanal</a></strong> - Conoce todos los canales de comunicación compatibles con Clawdbot y sus características, domina los conceptos básicos de configuración de canales.</li></ul><h3 id="canales-de-mensajeria-instantanea" tabindex="-1">Canales de Mensajería Instantánea <a class="header-anchor" href="#canales-de-mensajeria-instantanea" aria-label="Permalink to &quot;Canales de Mensajería Instantánea&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - Configurar y usar el canal de WhatsApp (basado en Baileys), soporta vinculación de dispositivos y gestión de grupos.</li><li><strong><a href="./telegram/">Telegram</a></strong> - Configurar y usar el canal de Telegram (basado en grammY Bot API), configurar Bot Token y Webhook.</li><li><strong><a href="./slack/">Slack</a></strong> - Configurar y usar el canal de Slack (basado en Bolt), integrar en tu espacio de trabajo.</li><li><strong><a href="./discord/">Discord</a></strong> - Configurar y usar el canal de Discord (basado en discord.js), soporta servidores y canales.</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Configurar y usar el canal de Google Chat, integrar con Google Workspace.</li><li><strong><a href="./signal/">Signal</a></strong> - Configurar y usar el canal de Signal (basado en signal-cli), comunicación con privacidad protegida.</li><li><strong><a href="./imessage/">iMessage</a></strong> - Configurar y usar el canal de iMessage (exclusivo de macOS), integrar con la aplicación Mensajes de macOS.</li><li><strong><a href="./line/">LINE</a></strong> - Configurar y usar el canal de LINE (Messaging API), interactuar con usuarios de LINE.</li></ul><h3 id="web-y-aplicaciones-nativas" tabindex="-1">Web y Aplicaciones Nativas <a class="header-anchor" href="#web-y-aplicaciones-nativas" aria-label="Permalink to &quot;Web y Aplicaciones Nativas&quot;">​</a></h3><ul><li><strong><a href="./webchat/">Interfaz WebChat</a></strong> - Usar la interfaz WebChat incorporada para interactuar con el asistente de IA, sin necesidad de configurar canales externos.</li><li><strong><a href="./macos-app/">Aplicación macOS</a></strong> - Conocer las funciones de la aplicación de barra de menús de macOS, incluyendo Voice Wake, Talk Mode y control remoto.</li><li><strong><a href="./ios-node/">Nodo iOS</a></strong> - Configurar el nodo iOS para ejecutar operaciones locales en el dispositivo (Camera, Canvas, Voice Wake).</li><li><strong><a href="./android-node/">Nodo Android</a></strong> - Configurar el nodo Android para ejecutar operaciones locales en el dispositivo (Camera, Canvas).</li></ul><h2 id="ruta-de-aprendizaje-recomendada" tabindex="-1">Ruta de Aprendizaje Recomendada <a class="header-anchor" href="#ruta-de-aprendizaje-recomendada" aria-label="Permalink to &quot;Ruta de Aprendizaje Recomendada&quot;">​</a></h2><p>Según tu escenario de uso, se recomienda el siguiente orden de aprendizaje:</p><h3 id="inicio-rapido-para-principiantes" tabindex="-1">Inicio Rápido para Principiantes <a class="header-anchor" href="#inicio-rapido-para-principiantes" aria-label="Permalink to &quot;Inicio Rápido para Principiantes&quot;">​</a></h3><p>Si es la primera vez que usas Clawdbot, se recomienda seguir este orden:</p><ol><li><strong><a href="./channels-overview/">Visión General del Sistema Multicanal</a></strong> - Primero entiende la arquitectura general y los conceptos de canales</li><li><strong><a href="./webchat/">Interfaz WebChat</a></strong> - La forma más simple, sin necesidad de configuración para comenzar a usar</li><li><strong><a href="./whatsapp/">Elige un canal común</a></strong> - Según tus hábitos diarios elige: <ul><li>Chat diario → <a href="./whatsapp/">WhatsApp</a> o <a href="./telegram/">Telegram</a></li><li>Colaboración en equipo → <a href="./slack/">Slack</a> o <a href="./discord/">Discord</a></li><li>Usuario de macOS → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="integracion-movil" tabindex="-1">Integración Móvil <a class="header-anchor" href="#integracion-movil" aria-label="Permalink to &quot;Integración Móvil&quot;">​</a></h3><p>Si quieres usar Clawdbot en tu teléfono:</p><ol><li><strong><a href="./ios-node/">Nodo iOS</a></strong> - Configurar funciones locales en iPhone/iPad</li><li><strong><a href="./android-node/">Nodo Android</a></strong> - Configurar funciones locales en dispositivos Android</li><li><strong><a href="./macos-app/">Aplicación macOS</a></strong> - Usar la aplicación macOS como centro de control</li></ol><h3 id="despliegue-empresarial" tabindex="-1">Despliegue Empresarial <a class="header-anchor" href="#despliegue-empresarial" aria-label="Permalink to &quot;Despliegue Empresarial&quot;">​</a></h3><p>Si necesitas desplegar en un entorno de equipo:</p><ol><li><strong><a href="./slack/">Slack</a></strong> - Integrar con el espacio de trabajo del equipo</li><li><strong><a href="./discord/">Discord</a></strong> - Establecer un servidor comunitario</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Integrar con Google Workspace</li></ol><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><p>Antes de comenzar este capítulo, se recomienda completar primero:</p><ul><li><strong><a href="./../start/getting-started/">Inicio Rápido</a></strong> - Completar la instalación y configuración básica de Clawdbot</li><li><strong><a href="./../start/onboarding-wizard/">Configuración Asistida</a></strong> - Completar la configuración básica de Gateway y canales a través del asistente</li></ul><div class="tip custom-block"><p class="custom-block-title">Sugerencia</p><p>Si ya has completado la configuración asistida, algunos canales pueden estar ya configurados automáticamente. Puedes omitir los pasos de configuración repetidos y consultar directamente las funciones avanzadas de canales específicos.</p></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar explorando:</p><ul><li><strong><a href="./../advanced/models-auth/">Configuración de Modelos de IA y Autenticación</a></strong> - Configurar diferentes proveedores de modelos de IA</li><li><strong><a href="./../advanced/session-management/">Gestión de Sesiones y Multi-Agent</a></strong> - Aprender sobre aislamiento de sesiones y colaboración de sub-agentes</li><li><strong><a href="./../advanced/tools-browser/">Sistema de Herramientas</a></strong> - Usar herramientas como automatización de navegador, ejecución de comandos, etc.</li></ul><h2 id="preguntas-frecuentes" tabindex="-1">Preguntas Frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas Frecuentes&quot;">​</a></h2><details class="details custom-block"><summary>¿Puedo usar múltiples canales simultáneamente?</summary><p>¡Sí! Clawdbot admite habilitar múltiples canales simultáneamente. Puedes recibir y enviar mensajes en diferentes canales, todos los mensajes se procesan a través del Gateway unificado.</p></details><details class="details custom-block"><summary>¿Qué canal se recomienda más?</summary><p>Depende de tu escenario de uso:</p><ul><li><strong>WebChat</strong> - Lo más simple, sin necesidad de configuración</li><li><strong>WhatsApp</strong> - Adecuado para chatear con amigos y familiares</li><li><strong>Telegram</strong> - Bot API estable, adecuado para respuestas automáticas</li><li><strong>Slack/Discord</strong> - Adecuado para colaboración en equipo</li></ul></details><details class="details custom-block"><summary>¿Configurar canales requiere pago?</summary><p>La mayoría de los canales son gratuitos, pero algunos pueden tener costos:</p><ul><li>WhatsApp Business API - Puede generar costos</li><li>Google Chat - Requiere cuenta de Google Workspace</li><li>Otros canales - Generalmente gratuitos, solo necesitan solicitar Bot Token</li></ul></details>',33)])])}const m=e(n,[["render",r]]);export{g as __pageData,m as default};
